import{_ as t,o as l,c as e,a4 as s}from"./chunks/framework._in6GHBg.js";const c=JSON.parse('{"title":"阅读理解套路","description":"","frontmatter":{},"headers":[],"relativePath":"english/Eng-Review-Routine-003-阅读理解套路-V1.0-20260405.md","filePath":"english/Eng-Review-Routine-003-阅读理解套路-V1.0-20260405.md"}'),n={name:"english/Eng-Review-Routine-003-阅读理解套路-V1.0-20260405.md"};function i(o,a,r,h,p,d){return l(),e("div",null,[...a[0]||(a[0]=[s(`<h1 id="阅读理解套路" tabindex="-1">阅读理解套路 <a class="header-anchor" href="#阅读理解套路" aria-label="Permalink to &quot;阅读理解套路&quot;">​</a></h1><p><strong>快速定位→精准理解→逻辑判断</strong></p><hr><h2 id="一、题型识别" tabindex="-1">一、题型识别 <a class="header-anchor" href="#一、题型识别" aria-label="Permalink to &quot;一、题型识别&quot;">​</a></h2><h3 id="常见题型-四大类" tabindex="-1">常见题型（四大类） <a class="header-anchor" href="#常见题型-四大类" aria-label="Permalink to &quot;常见题型（四大类）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">题型</th><th style="text-align:left;">特征</th><th style="text-align:center;">占比</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>细节理解题</strong></td><td style="text-align:left;">What/When/Where/Who/How</td><td style="text-align:center;">约50%</td></tr><tr><td style="text-align:center;"><strong>推理判断题</strong></td><td style="text-align:left;">infer/imply/suggest/indicate</td><td style="text-align:center;">约25%</td></tr><tr><td style="text-align:center;"><strong>主旨大意题</strong></td><td style="text-align:left;">main idea/title/subject</td><td style="text-align:center;">约15%</td></tr><tr><td style="text-align:center;"><strong>词义猜测题</strong></td><td style="text-align:left;">划线单词/短语含义</td><td style="text-align:center;">约10%</td></tr></tbody></table><hr><h2 id="二、解题步骤" tabindex="-1">二、解题步骤 <a class="header-anchor" href="#二、解题步骤" aria-label="Permalink to &quot;二、解题步骤&quot;">​</a></h2><h3 id="step-1-快速浏览-抓主旨-1-2分钟" tabindex="-1">Step 1：快速浏览，抓主旨（1-2分钟） <a class="header-anchor" href="#step-1-快速浏览-抓主旨-1-2分钟" aria-label="Permalink to &quot;Step 1：快速浏览，抓主旨（1-2分钟）&quot;">​</a></h3><p><strong>读什么</strong>：</p><ul><li>标题（如有）</li><li>首尾段</li><li>每段首句</li></ul><p><strong>目的</strong>：</p><ul><li>了解文章主题</li><li>把握文章结构</li></ul><hr><h3 id="step-2-看题目-划关键词" tabindex="-1">Step 2：看题目，划关键词 <a class="header-anchor" href="#step-2-看题目-划关键词" aria-label="Permalink to &quot;Step 2：看题目，划关键词&quot;">​</a></h3><p><strong>关键词类型</strong>：</p><ul><li>人名、地名、数字、时间</li><li>大写字母、引号内的词</li><li>核心概念词</li></ul><p><strong>示例</strong>：</p><ul><li>题目：What did <strong>John Smith</strong> say about <strong>climate change</strong> in <strong>2019</strong>?</li><li>关键词：John Smith, climate change, 2019</li></ul><hr><h3 id="step-3-定位原文-找答案" tabindex="-1">Step 3：定位原文，找答案 <a class="header-anchor" href="#step-3-定位原文-找答案" aria-label="Permalink to &quot;Step 3：定位原文，找答案&quot;">​</a></h3><p><strong>定位方法</strong>：</p><ul><li>顺序原则：题目顺序与文章顺序基本一致</li><li>关键词定位：在原文中找到关键词或其同义词</li><li>段落定位：根据题目中的段落提示</li></ul><p><strong>注意</strong>：</p><ul><li>找到定位句后，仔细阅读前后句</li><li>答案通常在定位句或其附近</li></ul><hr><h3 id="step-4-同义替换-确定选项" tabindex="-1">Step 4：同义替换，确定选项 <a class="header-anchor" href="#step-4-同义替换-确定选项" aria-label="Permalink to &quot;Step 4：同义替换，确定选项&quot;">​</a></h3><p><strong>正确答案特征</strong>：</p><ul><li>原文的同义改写</li><li>不是原文原词照搬（细节题除外）</li><li>符合文章主旨</li></ul><p><strong>常见替换</strong>：</p><ul><li>词性转换：important → importance</li><li>同义词：big → large/huge</li><li>反义词+否定：not small = big</li><li>概括：apple, banana, orange → fruit</li></ul><hr><h2 id="三、各题型解题技巧" tabindex="-1">三、各题型解题技巧 <a class="header-anchor" href="#三、各题型解题技巧" aria-label="Permalink to &quot;三、各题型解题技巧&quot;">​</a></h2><h3 id="_3-1-细节理解题-⭐" tabindex="-1">3.1 细节理解题 ⭐ <a class="header-anchor" href="#_3-1-细节理解题-⭐" aria-label="Permalink to &quot;3.1 细节理解题 ⭐&quot;">​</a></h3><p><strong>问法</strong>：</p><ul><li>According to the passage, ...</li><li>What do we know about...?</li><li>Which of the following is TRUE?</li></ul><p><strong>技巧</strong>：</p><ol><li>准确定位原文</li><li>仔细比对选项</li><li>注意偷换概念（张冠李戴）</li></ol><p><strong>示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原文：The study found that students who slept 8 hours performed better than those who slept 6 hours.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>题目：What did the study find?</span></span>
<span class="line"><span>A. Students should sleep 10 hours. （无依据）</span></span>
<span class="line"><span>B. 8 hours of sleep is better than 6 hours for students. （同义改写）</span></span>
<span class="line"><span>C. Sleeping less improves performance. （相反）</span></span>
<span class="line"><span>D. All students performed well. （扩大范围）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>答案：B</span></span></code></pre></div><hr><h3 id="_3-2-推理判断题-⭐" tabindex="-1">3.2 推理判断题 ⭐ <a class="header-anchor" href="#_3-2-推理判断题-⭐" aria-label="Permalink to &quot;3.2 推理判断题 ⭐&quot;">​</a></h3><p><strong>问法</strong>：</p><ul><li>We can infer from the passage that...</li><li>The author implies that...</li><li>What can be concluded from...?</li></ul><p><strong>技巧</strong>：</p><ol><li>答案不是原文直接说的</li><li>是根据原文信息推出的</li><li>过度推断的选项不选</li></ol><p><strong>常见陷阱</strong>：</p><ul><li>原文直接说的（不是推断）</li><li>过度推断（推得太远）</li><li>与原文相反</li></ul><p><strong>示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原文：The price of oil has risen by 30% this year.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>题目：What can we infer?</span></span>
<span class="line"><span>A. Oil price has risen by 30%. （原文直接说，不是推断）</span></span>
<span class="line"><span>B. The oil price may continue to rise. （可能，合理推断）</span></span>
<span class="line"><span>C. People will stop using oil. （过度推断）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>答案：B</span></span></code></pre></div><hr><h3 id="_3-3-主旨大意题" tabindex="-1">3.3 主旨大意题 <a class="header-anchor" href="#_3-3-主旨大意题" aria-label="Permalink to &quot;3.3 主旨大意题&quot;">​</a></h3><p><strong>问法</strong>：</p><ul><li>What is the main idea of the passage?</li><li>The best title for the passage is...</li><li>What is the passage mainly about?</li></ul><p><strong>技巧</strong>：</p><ol><li>看首尾段（尤其是首段）</li><li>看每段首句</li><li>不要被细节迷惑</li><li>标题要概括全文，不能太宽泛或太具体</li></ol><p><strong>错误选项特征</strong>：</p><ul><li>以偏概全（只讲某一段内容）</li><li>无中生有（文中没有）</li><li>扩大范围</li></ul><hr><h3 id="_3-4-词义猜测题" tabindex="-1">3.4 词义猜测题 <a class="header-anchor" href="#_3-4-词义猜测题" aria-label="Permalink to &quot;3.4 词义猜测题&quot;">​</a></h3><p><strong>问法</strong>：</p><ul><li>The word &quot;...&quot; in Paragraph X probably means...</li><li>What does the underlined word refer to?</li></ul><p><strong>技巧</strong>：</p><ol><li>看前后句（定义、解释、举例）</li><li>看逻辑关系（同义、反义、因果）</li><li>代入验证</li></ol><p><strong>线索类型</strong>：</p><ul><li>定义：..., which means...</li><li>解释：...; that is to say, ...</li><li>举例：..., such as/for example...</li><li>同义：and, also, similarly</li><li>反义：but, however, while</li></ul><p><strong>示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原文：The doctor was late because of a detour—a longer route taken to avoid traffic.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>题目：What does &quot;detour&quot; mean?</span></span>
<span class="line"><span>A. 捷径 （反义）</span></span>
<span class="line"><span>B. 绕路 （解释）</span></span>
<span class="line"><span>C. 堵车 （原因）</span></span>
<span class="line"><span>D. 迟到 （结果）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>答案：B</span></span></code></pre></div><hr><h2 id="四、七选五解题技巧" tabindex="-1">四、七选五解题技巧 <a class="header-anchor" href="#四、七选五解题技巧" aria-label="Permalink to &quot;四、七选五解题技巧&quot;">​</a></h2><h3 id="_4-1-题型特点" tabindex="-1">4.1 题型特点 <a class="header-anchor" href="#_4-1-题型特点" aria-label="Permalink to &quot;4.1 题型特点&quot;">​</a></h3><ul><li>给出一篇文章，挖出5个空</li><li>提供7个选项，选5个填入</li><li>考查语篇衔接和逻辑关系</li></ul><h3 id="_4-2-解题步骤" tabindex="-1">4.2 解题步骤 <a class="header-anchor" href="#_4-2-解题步骤" aria-label="Permalink to &quot;4.2 解题步骤&quot;">​</a></h3><ol><li><strong>看选项</strong>：划出选项关键词</li><li><strong>读文章</strong>：把握主旨和结构</li><li><strong>看空格位置</strong>： <ul><li>段首：主题句</li><li>段中：过渡或例证</li><li>段尾：总结或过渡</li></ul></li><li><strong>找线索</strong>： <ul><li>代词指代（it, they, this, that）</li><li>逻辑词（however, therefore, in addition）</li><li>词汇复现（同词、同义词、反义词）</li></ul></li></ol><hr><h2 id="五、标准格式" tabindex="-1">五、标准格式 <a class="header-anchor" href="#五、标准格式" aria-label="Permalink to &quot;五、标准格式&quot;">​</a></h2><h3 id="做题标记法" tabindex="-1">做题标记法 <a class="header-anchor" href="#做题标记法" aria-label="Permalink to &quot;做题标记法&quot;">​</a></h3><p><strong>在原文中标记</strong>：</p><ul><li>圈出关键词</li><li>划出答案依据句</li><li>标出题号</li></ul><p><strong>方便</strong>：</p><ul><li>检查时有依据</li><li>修改时知道原思路</li></ul><hr><h2 id="六、典型例题" tabindex="-1">六、典型例题 <a class="header-anchor" href="#六、典型例题" aria-label="Permalink to &quot;六、典型例题&quot;">​</a></h2><h3 id="例题1-细节题" tabindex="-1">例题1：细节题 <a class="header-anchor" href="#例题1-细节题" aria-label="Permalink to &quot;例题1：细节题&quot;">​</a></h3><p><strong>原文</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Researchers at Harvard University found that people who read books regularly live longer than those who don&#39;t read at all. The study followed 3,635 people for 12 years.</span></span></code></pre></div><p><strong>题目</strong>：How many people were involved in the study? A. 635<br> B. 3,635<br> C. 12<br> D. Not mentioned</p><p><strong>解析</strong>：直接定位数字，答案是B。</p><hr><h3 id="例题2-推理题" tabindex="-1">例题2：推理题 <a class="header-anchor" href="#例题2-推理题" aria-label="Permalink to &quot;例题2：推理题&quot;">​</a></h3><p><strong>原文</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>John didn&#39;t say a word during the whole meeting. He just sat there with his arms crossed.</span></span></code></pre></div><p><strong>题目</strong>：What can we infer about John&#39;s attitude? A. He was excited.<br> B. He was supportive.<br> C. He was unhappy or opposed.<br> D. He was tired.</p><p><strong>解析</strong>：不说一句话、双臂交叉，暗示不满或反对，答案是C。</p><hr><h2 id="七、易错点清单" tabindex="-1">七、易错点清单 <a class="header-anchor" href="#七、易错点清单" aria-label="Permalink to &quot;七、易错点清单&quot;">​</a></h2><h3 id="审题阶段" tabindex="-1">审题阶段 <a class="header-anchor" href="#审题阶段" aria-label="Permalink to &quot;审题阶段&quot;">​</a></h3><ul><li>[ ] 注意题目问的是&quot;正确&quot;还是&quot;不正确&quot;</li><li>[ ] 注意是&quot;作者观点&quot;还是&quot;他人观点&quot;</li><li>[ ] 注意时间、地点等限定词</li></ul><h3 id="做题阶段" tabindex="-1">做题阶段 <a class="header-anchor" href="#做题阶段" aria-label="Permalink to &quot;做题阶段&quot;">​</a></h3><ul><li>[ ] 是否找到原文依据？</li><li>[ ] 是否注意同义替换？</li><li>[ ] 是否以偏概全？</li></ul><h3 id="检查阶段" tabindex="-1">检查阶段 <a class="header-anchor" href="#检查阶段" aria-label="Permalink to &quot;检查阶段&quot;">​</a></h3><ul><li>[ ] 推理题是否推得过度？</li><li>[ ] 主旨题是否被细节迷惑？</li><li>[ ] 是否漏看题目要求？</li></ul><hr><h2 id="八、练习建议" tabindex="-1">八、练习建议 <a class="header-anchor" href="#八、练习建议" aria-label="Permalink to &quot;八、练习建议&quot;">​</a></h2><h3 id="训练步骤" tabindex="-1">训练步骤 <a class="header-anchor" href="#训练步骤" aria-label="Permalink to &quot;训练步骤&quot;">​</a></h3><ol><li><strong>不限时</strong>：保证准确率</li><li><strong>限时</strong>：逐渐提高速度（7-8分钟/篇）</li><li><strong>分析</strong>：错题归类，找出薄弱环节</li><li><strong>总结</strong>：积累同义替换、长难句</li></ol><h3 id="提高速度方法" tabindex="-1">提高速度方法 <a class="header-anchor" href="#提高速度方法" aria-label="Permalink to &quot;提高速度方法&quot;">​</a></h3><ul><li>不回读（一遍看懂）</li><li>不纠结（先标记，后回头）</li><li>多练习（熟能生巧）</li></ul><hr><p><strong>文档编号</strong>: Eng-Review-Routine-003<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,110)])])}const g=t(n,[["render",i]]);export{c as __pageData,g as default};
